BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'Pericarditis' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'Pericarditis', 'Inflammation, EKG changes, MI differential, treatment', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - Pericarditis (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'Pericarditis - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Definition in this high-acuity chest pain scenario?', 'Which finding most strongly supports Definition in this high-acuity chest pain scenario?', '[{"id": "a", "text": "Pericarditis is confined to coronary arteries in this note."}, {"id": "b", "text": "Pericarditis is inflammation of the pericardium, the fibrous sac surrounding the heart."}, {"id": "c", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "d", "text": "This pattern is more consistent with Common causes."}]'::jsonb, '["b"]'::jsonb, 'Correct because Pericarditis is inflammation of the pericardium, the fibrous sac surrounding the heart. Identify inflammatory pericardial pain patterns early to prevent complications.', 'Pericarditis - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for potential pericarditis. Which interpretation best matches Disease course?', 'The nurse reviews data for potential pericarditis. Which interpretation best matches Disease course?', '[{"id": "a", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "b", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "c", "text": "This pattern is more consistent with Systemic/infectious causes."}, {"id": "d", "text": "Recurrent patterns require recurrence-prevention therapy and follow-up."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pericarditis can be acute, recurrent, or chronic constrictive. Recurrent patterns require recurrence-prevention therapy and follow-up.', 'Pericarditis - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Effusion complication?', 'Which clinical judgment is most accurate regarding Effusion complication?', '[{"id": "a", "text": "This pattern is more consistent with Dressler syndrome timing."}, {"id": "b", "text": "Effusion improves cardiac filling in this note."}, {"id": "c", "text": "Fluid accumulation can cause pericardial effusion, and large effusions can lead to cardiac tamponade."}, {"id": "d", "text": "Tamponade is a harmless expected phase in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Fluid accumulation can cause pericardial effusion, and large effusions can lead to cardiac tamponade. Escalate promptly when effusion signs appear because tamponade is life-threatening.', 'Pericarditis - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which statement is most consistent with Common causes?', 'In rapid prioritization, which statement is most consistent with Common causes?', '[{"id": "a", "text": "Pericarditis is almost never viral in this note."}, {"id": "b", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "c", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "d", "text": "Prioritize broad etiologic review while managing inflammation and pain."}]'::jsonb, '["d"]'::jsonb, 'Correct because Viral causes are most common, and many cases are idiopathic. Prioritize broad etiologic review while managing inflammation and pain.', 'Pericarditis - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion best aligns with Systemic/infectious causes from current assessment findings?', 'Which conclusion best aligns with Systemic/infectious causes from current assessment findings?', '[{"id": "a", "text": "Radiation cannot cause pericarditis in this note."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "Bacterial TB/S. aureus, autoimmune disease, uremia, malignancy, radiation, trauma, surgery, and medications are listed causes."}, {"id": "d", "text": "The best approach is to defer EKG differentiation until outpatient review."}]'::jsonb, '["c"]'::jsonb, 'Correct because Bacterial TB/S. aureus, autoimmune disease, uremia, malignancy, radiation, trauma, surgery, and medications are listed causes. Tailor treatment to the underlying cause while controlling inflammation.', 'Pericarditis - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Dressler syndrome timing in this high-acuity chest pain scenario?', 'Which finding most strongly supports Dressler syndrome timing in this high-acuity chest pain scenario?', '[{"id": "a", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "b", "text": "Recognize delayed post-MI/surgical chest pain as possible Dressler syndrome."}, {"id": "c", "text": "Dressler syndrome occurs immediately during MI in this note."}, {"id": "d", "text": "This pattern is more consistent with Friction rub hallmark."}]'::jsonb, '["b"]'::jsonb, 'Correct because Dressler syndrome is autoimmune pericarditis occurring 1–6 weeks after MI or cardiac surgery. Recognize delayed post-MI/surgical chest pain as possible Dressler syndrome.', 'Pericarditis - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for potential pericarditis. Which interpretation best matches Classic pain profile?', 'The nurse reviews data for potential pericarditis. Which interpretation best matches Classic pain profile?', '[{"id": "a", "text": "This pattern is more consistent with Rub nuances."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "Leaning forward worsens pain in this note."}, {"id": "d", "text": "Pericarditis pain is sharp/pleuritic, worse with inspiration and lying flat, and relieved by sitting up/leaning forward."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pericarditis pain is sharp/pleuritic, worse with inspiration and lying flat, and relieved by sitting up/leaning forward. Use positional and pleuritic features to distinguish from ischemic chest pain patterns.', 'Pericarditis - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Radiation and associated symptoms?', 'Which clinical judgment is most accurate regarding Radiation and associated symptoms?', '[{"id": "a", "text": "Dyspnea never occurs in pericarditis in this note."}, {"id": "b", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "c", "text": "Link systemic symptoms with inflammatory etiology during triage."}, {"id": "d", "text": "Trapezius radiation excludes pericarditis in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pain can radiate to left shoulder/trapezius; fever, malaise, myalgia, and dyspnea can occur. Link systemic symptoms with inflammatory etiology during triage.', 'Pericarditis - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which statement is most consistent with Friction rub hallmark?', 'In rapid prioritization, which statement is most consistent with Friction rub hallmark?', '[{"id": "a", "text": "Rub is best heard at the carotids in this note."}, {"id": "b", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "c", "text": "Pericardial friction rub is pathognomonic: high-pitched scratchy/grating, best heard at left sternal border with patient leaning forward."}, {"id": "d", "text": "Friction rub is a definitive MI finding in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pericardial friction rub is pathognomonic: high-pitched scratchy/grating, best heard at left sternal border with patient leaning forward. Prioritize focused auscultation technique to capture fleeting rub findings.', 'Pericarditis - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion best aligns with Rub nuances from current assessment findings?', 'Which conclusion best aligns with Rub nuances from current assessment findings?', '[{"id": "a", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "b", "text": "Do not rule out pericarditis solely because rub is absent later in disease."}, {"id": "c", "text": "This pattern is more consistent with No reciprocal changes."}, {"id": "d", "text": "The best approach is to defer EKG differentiation until outpatient review."}]'::jsonb, '["b"]'::jsonb, 'Correct because The rub may be triphasic and can disappear if effusion develops as fluid separates pericardial layers. Do not rule out pericarditis solely because rub is absent later in disease.', 'Pericarditis - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Diffuse ST elevation in this high-acuity chest pain scenario?', 'Which finding most strongly supports Diffuse ST elevation in this high-acuity chest pain scenario?', '[{"id": "a", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "b", "text": "This pattern is more consistent with Later EKG evolution."}, {"id": "c", "text": "ST elevation is absent in pericarditis in this note."}, {"id": "d", "text": "Pericarditis classically shows diffuse (all-lead) saddle-shaped ST elevation."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pericarditis classically shows diffuse (all-lead) saddle-shaped ST elevation. Differentiate diffuse inflammatory ST elevation from territorial ischemic patterns.', 'Pericarditis - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for potential pericarditis. Which interpretation best matches PR depression?', 'The nurse reviews data for potential pericarditis. Which interpretation best matches PR depression?', '[{"id": "a", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "b", "text": "PR changes are irrelevant in pericarditis in this note."}, {"id": "c", "text": "This pattern is more consistent with Pericarditis vs MI pain differences."}, {"id": "d", "text": "Use PR deviation as a high-yield discriminator in early interpretation."}]'::jsonb, '["d"]'::jsonb, 'Correct because PR depression is a classic early pericarditis finding and opposite ST direction. Use PR deviation as a high-yield discriminator in early interpretation.', 'Pericarditis - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding No reciprocal changes?', 'Which clinical judgment is most accurate regarding No reciprocal changes?', '[{"id": "a", "text": "Reciprocal changes have no differential value in this note."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "Pericarditis has no reciprocal ST depression, unlike MI."}, {"id": "d", "text": "The best approach is to defer EKG differentiation until outpatient review."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pericarditis has no reciprocal ST depression, unlike MI. Avoid mislabeling diffuse pericarditis as STEMI when reciprocal changes are absent.', 'Pericarditis - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which statement is most consistent with Later EKG evolution?', 'In rapid prioritization, which statement is most consistent with Later EKG evolution?', '[{"id": "a", "text": "EKG pattern is fixed and never evolves in this note."}, {"id": "b", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "c", "text": "Electrical alternans excludes effusion in this note."}, {"id": "d", "text": "Interpret EKG changes in temporal context and effusion severity."}]'::jsonb, '["d"]'::jsonb, 'Correct because T-wave inversion may appear in later stages; electrical alternans can appear with large effusion. Interpret EKG changes in temporal context and effusion severity.', 'Pericarditis - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion best aligns with Pericarditis vs MI pain differences from current assessment findings?', 'Which conclusion best aligns with Pericarditis vs MI pain differences from current assessment findings?', '[{"id": "a", "text": "MI pain improves when leaning forward in this note."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "Pericarditis pain is gradual, sharp, pleuritic, and positional; MI pain is sudden, crushing, pressure-like, and non-positional."}, {"id": "d", "text": "The best approach is to defer EKG differentiation until outpatient review."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pericarditis pain is gradual, sharp, pleuritic, and positional; MI pain is sudden, crushing, pressure-like, and non-positional. Use symptom quality and positional response to sharpen early triage decisions.', 'Pericarditis - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Pericarditis vs MI EKG/lab clues in this high-acuity chest pain scenario?', 'Which finding most strongly supports Pericarditis vs MI EKG/lab clues in this high-acuity chest pain scenario?', '[{"id": "a", "text": "Integrate EKG with biomarker pattern to avoid anchoring errors."}, {"id": "b", "text": "Q waves are a pericarditis hallmark in this note."}, {"id": "c", "text": "Troponin is never elevated in any pericarditis scenario in this note."}, {"id": "d", "text": "The best approach is to defer EKG differentiation until outpatient review."}]'::jsonb, '["a"]'::jsonb, 'Correct because Pericarditis: diffuse ST elevation + PR depression + absent Q waves; MI: localized ST elevation, reciprocal changes, Q waves in STEMI, higher troponin rise. Integrate EKG with biomarker pattern to avoid anchoring errors.', 'Pericarditis - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for potential pericarditis. Which interpretation best matches First-line therapy?', 'The nurse reviews data for potential pericarditis. Which interpretation best matches First-line therapy?', '[{"id": "a", "text": "Opioids are listed as definitive first-line therapy in this note."}, {"id": "b", "text": "First-line treatment is NSAIDs (ibuprofen/aspirin) plus colchicine to reduce recurrence risk."}, {"id": "c", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "d", "text": "Immediate escalation is unnecessary because complication risk is negligible."}]'::jsonb, '["b"]'::jsonb, 'Correct because First-line treatment is NSAIDs (ibuprofen/aspirin) plus colchicine to reduce recurrence risk. Start anti-inflammatory therapy early and include recurrence prevention.', 'Pericarditis - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Activity guidance?', 'Which clinical judgment is most accurate regarding Activity guidance?', '[{"id": "a", "text": "This pattern is more consistent with Tamponade emergency bridge."}, {"id": "b", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "c", "text": "Prevent recurrence/worsening by enforcing temporary exertion limits."}, {"id": "d", "text": "No activity limits are needed during acute phase in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Rest and activity restriction are recommended during the acute phase; avoid strenuous exercise until symptom-free. Prevent recurrence/worsening by enforcing temporary exertion limits.', 'Pericarditis - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which statement is most consistent with Second-line steroids?', 'In rapid prioritization, which statement is most consistent with Second-line steroids?', '[{"id": "a", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "b", "text": "This pattern is more consistent with Dressler management caveat."}, {"id": "c", "text": "Corticosteroids are reserved when NSAID/colchicine fails or for specific causes like SLE."}, {"id": "d", "text": "Steroids are mandatory first-line for all cases in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Corticosteroids are reserved when NSAID/colchicine fails or for specific causes like SLE. Use steroids selectively to avoid unnecessary exposure and recurrence risk concerns.', 'Pericarditis - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion best aligns with Cause-specific caveats from current assessment findings?', 'Which conclusion best aligns with Cause-specific caveats from current assessment findings?', '[{"id": "a", "text": "This pattern is more consistent with NCLEX triage anchor."}, {"id": "b", "text": "Adapt treatment to etiology instead of one-size-fits-all prescribing."}, {"id": "c", "text": "TB management is excluded from pericarditis care in this note."}, {"id": "d", "text": "All causes are treated identically with NSAID monotherapy in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Avoid NSAIDs in uremic pericarditis; use IV antibiotics for bacterial causes and anti-TB therapy for TB. Adapt treatment to etiology instead of one-size-fits-all prescribing.', 'Pericarditis - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Tamponade emergency bridge in this high-acuity chest pain scenario?', 'Which finding most strongly supports Tamponade emergency bridge in this high-acuity chest pain scenario?', '[{"id": "a", "text": "Beck triad excludes tamponade in this note."}, {"id": "b", "text": "Tamponade complication is identified by Beck triad and treated with emergency pericardiocentesis."}, {"id": "c", "text": "Tamponade in pericarditis is managed with observation only in this note."}, {"id": "d", "text": "The best approach is to defer EKG differentiation until outpatient review."}]'::jsonb, '["b"]'::jsonb, 'Correct because Tamponade complication is identified by Beck triad and treated with emergency pericardiocentesis. Escalate immediately when hypotension + JVD + muffled tones develop.', 'Pericarditis - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for potential pericarditis. Which interpretation best matches Dressler management caveat?', 'The nurse reviews data for potential pericarditis. Which interpretation best matches Dressler management caveat?', '[{"id": "a", "text": "Routine anticoagulation is first-line Dressler treatment in this note."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "Dressler treatment excludes NSAIDs in this note."}, {"id": "d", "text": "Prevent iatrogenic hemopericardium by avoiding anticoagulants in this context."}]'::jsonb, '["d"]'::jsonb, 'Correct because Dressler syndrome is treated with NSAIDs + colchicine and anticoagulants are avoided due to bleeding risk into pericardium. Prevent iatrogenic hemopericardium by avoiding anticoagulants in this context.', 'Pericarditis - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding NCLEX triage anchor?', 'Which clinical judgment is most accurate regarding NCLEX triage anchor?', '[{"id": "a", "text": "This pattern is more consistent with Disease course."}, {"id": "b", "text": "Tamponade surveillance is unnecessary in pericarditis in this note."}, {"id": "c", "text": "In suspected pericarditis, prioritize pain pattern recognition, friction rub assessment, EKG interpretation, and tamponade surveillance."}, {"id": "d", "text": "Triage can ignore EKG in chest pain with suspected pericarditis in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because In suspected pericarditis, prioritize pain pattern recognition, friction rub assessment, EKG interpretation, and tamponade surveillance. Rapid differentiation from MI and early complication detection guide safe outcomes.', 'Pericarditis - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which statement is most consistent with Hallmark synthesis?', 'In rapid prioritization, which statement is most consistent with Hallmark synthesis?', '[{"id": "a", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "b", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "c", "text": "This pattern is more consistent with Effusion complication."}, {"id": "d", "text": "Synthesize multi-domain clues rather than relying on one isolated finding."}]'::jsonb, '["d"]'::jsonb, 'Correct because Core hallmarks are pleuritic positional chest pain, friction rub, diffuse ST elevation, PR depression, and absent reciprocal ST changes. Synthesize multi-domain clues rather than relying on one isolated finding.', 'Pericarditis - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion best aligns with Definition from current assessment findings?', 'Which conclusion best aligns with Definition from current assessment findings?', '[{"id": "a", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "b", "text": "This pattern is more consistent with Common causes."}, {"id": "c", "text": "Pericarditis is inflammation of heart valves in this note."}, {"id": "d", "text": "Pericarditis is inflammation of the pericardium, the fibrous sac surrounding the heart."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pericarditis is inflammation of the pericardium, the fibrous sac surrounding the heart. Identify inflammatory pericardial pain patterns early to prevent complications.', 'Pericarditis - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Disease course in this high-acuity chest pain scenario?', 'Which finding most strongly supports Disease course in this high-acuity chest pain scenario?', '[{"id": "a", "text": "This pattern is more consistent with Systemic/infectious causes."}, {"id": "b", "text": "Recurrent patterns require recurrence-prevention therapy and follow-up."}, {"id": "c", "text": "Constrictive disease is unrelated to pericarditis in this note."}, {"id": "d", "text": "The best approach is to defer EKG differentiation until outpatient review."}]'::jsonb, '["b"]'::jsonb, 'Correct because Pericarditis can be acute, recurrent, or chronic constrictive. Recurrent patterns require recurrence-prevention therapy and follow-up.', 'Pericarditis - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for potential pericarditis. Which interpretation best matches Effusion complication?', 'The nurse reviews data for potential pericarditis. Which interpretation best matches Effusion complication?', '[{"id": "a", "text": "Fluid accumulation can cause pericardial effusion, and large effusions can lead to cardiac tamponade."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "d", "text": "Effusion improves cardiac filling in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Fluid accumulation can cause pericardial effusion, and large effusions can lead to cardiac tamponade. Escalate promptly when effusion signs appear because tamponade is life-threatening.', 'Pericarditis - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Common causes?', 'Which clinical judgment is most accurate regarding Common causes?', '[{"id": "a", "text": "Pericarditis is almost never viral in this note."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "Prioritize broad etiologic review while managing inflammation and pain."}, {"id": "d", "text": "Idiopathic causes are excluded in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Viral causes are most common, and many cases are idiopathic. Prioritize broad etiologic review while managing inflammation and pain.', 'Pericarditis - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which statement is most consistent with Systemic/infectious causes?', 'In rapid prioritization, which statement is most consistent with Systemic/infectious causes?', '[{"id": "a", "text": "This pattern is more consistent with Radiation and associated symptoms."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "d", "text": "Bacterial TB/S. aureus, autoimmune disease, uremia, malignancy, radiation, trauma, surgery, and medications are listed causes."}]'::jsonb, '["d"]'::jsonb, 'Correct because Bacterial TB/S. aureus, autoimmune disease, uremia, malignancy, radiation, trauma, surgery, and medications are listed causes. Tailor treatment to the underlying cause while controlling inflammation.', 'Pericarditis - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion best aligns with Dressler syndrome timing from current assessment findings?', 'Which conclusion best aligns with Dressler syndrome timing from current assessment findings?', '[{"id": "a", "text": "Dressler syndrome is bacterial endocarditis in this note."}, {"id": "b", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "c", "text": "Recognize delayed post-MI/surgical chest pain as possible Dressler syndrome."}, {"id": "d", "text": "Dressler syndrome occurs immediately during MI in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Dressler syndrome is autoimmune pericarditis occurring 1–6 weeks after MI or cardiac surgery. Recognize delayed post-MI/surgical chest pain as possible Dressler syndrome.', 'Pericarditis - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Classic pain profile in this high-acuity chest pain scenario?', 'Which finding most strongly supports Classic pain profile in this high-acuity chest pain scenario?', '[{"id": "a", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "b", "text": "Leaning forward worsens pain in this note."}, {"id": "c", "text": "Pericarditis pain is sharp/pleuritic, worse with inspiration and lying flat, and relieved by sitting up/leaning forward."}, {"id": "d", "text": "Pain is position-independent pressure pain in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pericarditis pain is sharp/pleuritic, worse with inspiration and lying flat, and relieved by sitting up/leaning forward. Use positional and pleuritic features to distinguish from ischemic chest pain patterns.', 'Pericarditis - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for potential pericarditis. Which interpretation best matches Radiation and associated symptoms?', 'The nurse reviews data for potential pericarditis. Which interpretation best matches Radiation and associated symptoms?', '[{"id": "a", "text": "Link systemic symptoms with inflammatory etiology during triage."}, {"id": "b", "text": "Trapezius radiation excludes pericarditis in this note."}, {"id": "c", "text": "Dyspnea never occurs in pericarditis in this note."}, {"id": "d", "text": "This pattern is more consistent with Diffuse ST elevation."}]'::jsonb, '["a"]'::jsonb, 'Correct because Pain can radiate to left shoulder/trapezius; fever, malaise, myalgia, and dyspnea can occur. Link systemic symptoms with inflammatory etiology during triage.', 'Pericarditis - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Friction rub hallmark?', 'Which clinical judgment is most accurate regarding Friction rub hallmark?', '[{"id": "a", "text": "Rub is best heard at the carotids in this note."}, {"id": "b", "text": "Friction rub is a definitive MI finding in this note."}, {"id": "c", "text": "This pattern is more consistent with PR depression."}, {"id": "d", "text": "Pericardial friction rub is pathognomonic: high-pitched scratchy/grating, best heard at left sternal border with patient leaning forward."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pericardial friction rub is pathognomonic: high-pitched scratchy/grating, best heard at left sternal border with patient leaning forward. Prioritize focused auscultation technique to capture fleeting rub findings.', 'Pericarditis - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which statement is most consistent with Rub nuances?', 'In rapid prioritization, which statement is most consistent with Rub nuances?', '[{"id": "a", "text": "This pattern is more consistent with No reciprocal changes."}, {"id": "b", "text": "Do not rule out pericarditis solely because rub is absent later in disease."}, {"id": "c", "text": "Persistent rub is required throughout all stages in this note."}, {"id": "d", "text": "Immediate escalation is unnecessary because complication risk is negligible."}]'::jsonb, '["b"]'::jsonb, 'Correct because The rub may be triphasic and can disappear if effusion develops as fluid separates pericardial layers. Do not rule out pericarditis solely because rub is absent later in disease.', 'Pericarditis - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion best aligns with Diffuse ST elevation from current assessment findings?', 'Which conclusion best aligns with Diffuse ST elevation from current assessment findings?', '[{"id": "a", "text": "Pericarditis classically shows diffuse (all-lead) saddle-shaped ST elevation."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "d", "text": "ST elevation is absent in pericarditis in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Pericarditis classically shows diffuse (all-lead) saddle-shaped ST elevation. Differentiate diffuse inflammatory ST elevation from territorial ischemic patterns.', 'Pericarditis - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports PR depression in this high-acuity chest pain scenario?', 'Which finding most strongly supports PR depression in this high-acuity chest pain scenario?', '[{"id": "a", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "b", "text": "PR changes are irrelevant in pericarditis in this note."}, {"id": "c", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "d", "text": "Use PR deviation as a high-yield discriminator in early interpretation."}]'::jsonb, '["d"]'::jsonb, 'Correct because PR depression is a classic early pericarditis finding and opposite ST direction. Use PR deviation as a high-yield discriminator in early interpretation.', 'Pericarditis - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for potential pericarditis. Which interpretation best matches No reciprocal changes?', 'The nurse reviews data for potential pericarditis. Which interpretation best matches No reciprocal changes?', '[{"id": "a", "text": "Pericarditis has no reciprocal ST depression, unlike MI."}, {"id": "b", "text": "Pericarditis requires reciprocal ST depression in this note."}, {"id": "c", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "d", "text": "Reciprocal changes have no differential value in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Pericarditis has no reciprocal ST depression, unlike MI. Avoid mislabeling diffuse pericarditis as STEMI when reciprocal changes are absent.', 'Pericarditis - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Later EKG evolution?', 'Which clinical judgment is most accurate regarding Later EKG evolution?', '[{"id": "a", "text": "EKG pattern is fixed and never evolves in this note."}, {"id": "b", "text": "Electrical alternans excludes effusion in this note."}, {"id": "c", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "d", "text": "Interpret EKG changes in temporal context and effusion severity."}]'::jsonb, '["d"]'::jsonb, 'Correct because T-wave inversion may appear in later stages; electrical alternans can appear with large effusion. Interpret EKG changes in temporal context and effusion severity.', 'Pericarditis - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which statement is most consistent with Pericarditis vs MI pain differences?', 'In rapid prioritization, which statement is most consistent with Pericarditis vs MI pain differences?', '[{"id": "a", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "Pericarditis pain is gradual, sharp, pleuritic, and positional; MI pain is sudden, crushing, pressure-like, and non-positional."}, {"id": "d", "text": "Pericarditis pain is classically crushing pressure in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Pericarditis pain is gradual, sharp, pleuritic, and positional; MI pain is sudden, crushing, pressure-like, and non-positional. Use symptom quality and positional response to sharpen early triage decisions.', 'Pericarditis - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion best aligns with Pericarditis vs MI EKG/lab clues from current assessment findings?', 'Which conclusion best aligns with Pericarditis vs MI EKG/lab clues from current assessment findings?', '[{"id": "a", "text": "This pattern is more consistent with Second-line steroids."}, {"id": "b", "text": "Integrate EKG with biomarker pattern to avoid anchoring errors."}, {"id": "c", "text": "Troponin is never elevated in any pericarditis scenario in this note."}, {"id": "d", "text": "The best approach is to defer EKG differentiation until outpatient review."}]'::jsonb, '["b"]'::jsonb, 'Correct because Pericarditis: diffuse ST elevation + PR depression + absent Q waves; MI: localized ST elevation, reciprocal changes, Q waves in STEMI, higher troponin rise. Integrate EKG with biomarker pattern to avoid anchoring errors.', 'Pericarditis - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports First-line therapy in this high-acuity chest pain scenario?', 'Which finding most strongly supports First-line therapy in this high-acuity chest pain scenario?', '[{"id": "a", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "b", "text": "First-line treatment is NSAIDs (ibuprofen/aspirin) plus colchicine to reduce recurrence risk."}, {"id": "c", "text": "Colchicine is contraindicated in all pericarditis in this note."}, {"id": "d", "text": "This pattern is more consistent with Cause-specific caveats."}]'::jsonb, '["b"]'::jsonb, 'Correct because First-line treatment is NSAIDs (ibuprofen/aspirin) plus colchicine to reduce recurrence risk. Start anti-inflammatory therapy early and include recurrence prevention.', 'Pericarditis - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for potential pericarditis. Which interpretation best matches Activity guidance?', 'The nurse reviews data for potential pericarditis. Which interpretation best matches Activity guidance?', '[{"id": "a", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "b", "text": "No activity limits are needed during acute phase in this note."}, {"id": "c", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "d", "text": "Prevent recurrence/worsening by enforcing temporary exertion limits."}]'::jsonb, '["d"]'::jsonb, 'Correct because Rest and activity restriction are recommended during the acute phase; avoid strenuous exercise until symptom-free. Prevent recurrence/worsening by enforcing temporary exertion limits.', 'Pericarditis - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Second-line steroids?', 'Which clinical judgment is most accurate regarding Second-line steroids?', '[{"id": "a", "text": "SLE-related pericarditis should avoid steroids in this note."}, {"id": "b", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "c", "text": "Corticosteroids are reserved when NSAID/colchicine fails or for specific causes like SLE."}, {"id": "d", "text": "This pattern is more consistent with Dressler management caveat."}]'::jsonb, '["c"]'::jsonb, 'Correct because Corticosteroids are reserved when NSAID/colchicine fails or for specific causes like SLE. Use steroids selectively to avoid unnecessary exposure and recurrence risk concerns.', 'Pericarditis - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which statement is most consistent with Cause-specific caveats?', 'In rapid prioritization, which statement is most consistent with Cause-specific caveats?', '[{"id": "a", "text": "This pattern is more consistent with NCLEX triage anchor."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "TB management is excluded from pericarditis care in this note."}, {"id": "d", "text": "Adapt treatment to etiology instead of one-size-fits-all prescribing."}]'::jsonb, '["d"]'::jsonb, 'Correct because Avoid NSAIDs in uremic pericarditis; use IV antibiotics for bacterial causes and anti-TB therapy for TB. Adapt treatment to etiology instead of one-size-fits-all prescribing.', 'Pericarditis - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion best aligns with Tamponade emergency bridge from current assessment findings?', 'Which conclusion best aligns with Tamponade emergency bridge from current assessment findings?', '[{"id": "a", "text": "This pattern is more consistent with Hallmark synthesis."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "d", "text": "Tamponade complication is identified by Beck triad and treated with emergency pericardiocentesis."}]'::jsonb, '["d"]'::jsonb, 'Correct because Tamponade complication is identified by Beck triad and treated with emergency pericardiocentesis. Escalate immediately when hypotension + JVD + muffled tones develop.', 'Pericarditis - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Dressler management caveat in this high-acuity chest pain scenario?', 'Which finding most strongly supports Dressler management caveat in this high-acuity chest pain scenario?', '[{"id": "a", "text": "This pattern is more consistent with Definition."}, {"id": "b", "text": "Routine anticoagulation is first-line Dressler treatment in this note."}, {"id": "c", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "d", "text": "Prevent iatrogenic hemopericardium by avoiding anticoagulants in this context."}]'::jsonb, '["d"]'::jsonb, 'Correct because Dressler syndrome is treated with NSAIDs + colchicine and anticoagulants are avoided due to bleeding risk into pericardium. Prevent iatrogenic hemopericardium by avoiding anticoagulants in this context.', 'Pericarditis - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse reviews data for potential pericarditis. Which interpretation best matches NCLEX triage anchor?', 'The nurse reviews data for potential pericarditis. Which interpretation best matches NCLEX triage anchor?', '[{"id": "a", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "In suspected pericarditis, prioritize pain pattern recognition, friction rub assessment, EKG interpretation, and tamponade surveillance."}, {"id": "d", "text": "This pattern is more consistent with Disease course."}]'::jsonb, '["c"]'::jsonb, 'Correct because In suspected pericarditis, prioritize pain pattern recognition, friction rub assessment, EKG interpretation, and tamponade surveillance. Rapid differentiation from MI and early complication detection guide safe outcomes.', 'Pericarditis - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Hallmark synthesis?', 'Which clinical judgment is most accurate regarding Hallmark synthesis?', '[{"id": "a", "text": "This pattern is more consistent with Effusion complication."}, {"id": "b", "text": "Localized-only ST elevation is required for diagnosis in this note."}, {"id": "c", "text": "Synthesize multi-domain clues rather than relying on one isolated finding."}, {"id": "d", "text": "The best approach is to defer EKG differentiation until outpatient review."}]'::jsonb, '["c"]'::jsonb, 'Correct because Core hallmarks are pleuritic positional chest pain, friction rub, diffuse ST elevation, PR depression, and absent reciprocal ST changes. Synthesize multi-domain clues rather than relying on one isolated finding.', 'Pericarditis - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In rapid prioritization, which statement is most consistent with Definition?', 'In rapid prioritization, which statement is most consistent with Definition?', '[{"id": "a", "text": "The best approach is to defer EKG differentiation until outpatient review."}, {"id": "b", "text": "Pericarditis is confined to coronary arteries in this note."}, {"id": "c", "text": "This pattern is more consistent with Common causes."}, {"id": "d", "text": "Pericarditis is inflammation of the pericardium, the fibrous sac surrounding the heart."}]'::jsonb, '["d"]'::jsonb, 'Correct because Pericarditis is inflammation of the pericardium, the fibrous sac surrounding the heart. Identify inflammatory pericardial pain patterns early to prevent complications.', 'Pericarditis - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which conclusion best aligns with Disease course from current assessment findings?', 'Which conclusion best aligns with Disease course from current assessment findings?', '[{"id": "a", "text": "Recurrent patterns require recurrence-prevention therapy and follow-up."}, {"id": "b", "text": "Immediate escalation is unnecessary because complication risk is negligible."}, {"id": "c", "text": "Pericarditis is always single-episode and never recurrent in this note."}, {"id": "d", "text": "This pattern is more consistent with Systemic/infectious causes."}]'::jsonb, '["a"]'::jsonb, 'Correct because Pericarditis can be acute, recurrent, or chronic constrictive. Recurrent patterns require recurrence-prevention therapy and follow-up.', 'Pericarditis - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Inflammation can progress to pericardial effusion."}, {"id": "b", "text": "Pericarditis involves inflammation of pericardial layers."}, {"id": "c", "text": "Pericarditis is confined to coronary arteries in this note."}, {"id": "d", "text": "Pericarditis is inflammation of heart valves in this note."}, {"id": "e", "text": "The pericardium is the sac around the heart."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis is inflammation of the pericardium, the fibrous sac surrounding the heart.', 'Pericarditis - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected pericarditis and Disease course, which statements are correct? (Select all that apply)', 'For suspected pericarditis and Disease course, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Chronic constrictive forms are also listed."}, {"id": "b", "text": "Pericarditis is always single-episode and never recurrent in this note."}, {"id": "c", "text": "Recurrent forms are described in the note."}, {"id": "d", "text": "Constrictive disease is unrelated to pericarditis in this note."}, {"id": "e", "text": "Acute forms are described in the note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis can be acute, recurrent, or chronic constrictive.', 'Pericarditis - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Effusion complication. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Effusion complication. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Effusion improves cardiac filling in this note."}, {"id": "b", "text": "Pericardial inflammation can produce effusion."}, {"id": "c", "text": "Tamponade is a harmless expected phase in this note."}, {"id": "d", "text": "Tamponade is a life-threatening pericarditis complication."}, {"id": "e", "text": "Large effusions can compress the heart."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Fluid accumulation can cause pericardial effusion, and large effusions can lead to cardiac tamponade.', 'Pericarditis - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues support Common causes rather than MI? (Select all that apply)', 'Which clues support Common causes rather than MI? (Select all that apply)', '[{"id": "a", "text": "Viral etiologies are highlighted as most common."}, {"id": "b", "text": "Pericarditis is almost never viral in this note."}, {"id": "c", "text": "Idiopathic cases are frequent in this note."}, {"id": "d", "text": "Coxsackievirus/Echovirus/Influenza are listed viral examples."}, {"id": "e", "text": "Idiopathic causes are excluded in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Viral causes are most common, and many cases are idiopathic.', 'Pericarditis - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment of chest pain, which observations align with Systemic/infectious causes? (Select all that apply)', 'During reassessment of chest pain, which observations align with Systemic/infectious causes? (Select all that apply)', '[{"id": "a", "text": "TB and S. aureus are listed infectious causes."}, {"id": "b", "text": "Pericarditis is unrelated to renal failure in this note."}, {"id": "c", "text": "SLE/RA/scleroderma are autoimmune causes in the note."}, {"id": "d", "text": "Radiation cannot cause pericarditis in this note."}, {"id": "e", "text": "Hydralazine and Procainamide are listed medication causes."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Bacterial TB/S. aureus, autoimmune disease, uremia, malignancy, radiation, trauma, surgery, and medications are listed causes.', 'Pericarditis - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Dressler syndrome timing. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Dressler syndrome timing. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Dressler syndrome is bacterial endocarditis in this note."}, {"id": "b", "text": "Dressler syndrome can occur after MI."}, {"id": "c", "text": "Timing is listed as 1–6 weeks post-event."}, {"id": "d", "text": "Cardiac surgery is another trigger in this note."}, {"id": "e", "text": "Dressler syndrome occurs immediately during MI in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Dressler syndrome is autoimmune pericarditis occurring 1–6 weeks after MI or cardiac surgery.', 'Pericarditis - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected pericarditis and Classic pain profile, which statements are correct? (Select all that apply)', 'For suspected pericarditis and Classic pain profile, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Pain worsens when lying flat in this note."}, {"id": "b", "text": "Pain worsens with inspiration in this note."}, {"id": "c", "text": "Leaning forward worsens pain in this note."}, {"id": "d", "text": "Pain is position-independent pressure pain in this note."}, {"id": "e", "text": "Leaning forward provides relief in this note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis pain is sharp/pleuritic, worse with inspiration and lying flat, and relieved by sitting up/leaning forward.', 'Pericarditis - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Radiation and associated symptoms. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Radiation and associated symptoms. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Left shoulder/trapezius radiation is described."}, {"id": "b", "text": "Dyspnea never occurs in pericarditis in this note."}, {"id": "c", "text": "Trapezius radiation excludes pericarditis in this note."}, {"id": "d", "text": "Viral-associated constitutional symptoms may occur."}, {"id": "e", "text": "Dyspnea can accompany pericarditis."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pain can radiate to left shoulder/trapezius; fever, malaise, myalgia, and dyspnea can occur.', 'Pericarditis - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues support Friction rub hallmark rather than MI? (Select all that apply)', 'Which clues support Friction rub hallmark rather than MI? (Select all that apply)', '[{"id": "a", "text": "Best heard at left sternal border while leaning forward."}, {"id": "b", "text": "Friction rub is pathognomonic in this note."}, {"id": "c", "text": "The rub is described as high-pitched scratchy/grating."}, {"id": "d", "text": "Friction rub is a definitive MI finding in this note."}, {"id": "e", "text": "Rub is best heard at the carotids in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Pericardial friction rub is pathognomonic: high-pitched scratchy/grating, best heard at left sternal border with patient leaning forward.', 'Pericarditis - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment of chest pain, which observations align with Rub nuances? (Select all that apply)', 'During reassessment of chest pain, which observations align with Rub nuances? (Select all that apply)', '[{"id": "a", "text": "Triphasic friction rub may be present."}, {"id": "b", "text": "Loss of rub does not exclude worsening complications."}, {"id": "c", "text": "Rub can disappear when effusion increases."}, {"id": "d", "text": "Effusion makes rub louder by increasing friction in this note."}, {"id": "e", "text": "Persistent rub is required throughout all stages in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: The rub may be triphasic and can disappear if effusion develops as fluid separates pericardial layers.', 'Pericarditis - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Diffuse ST elevation. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Diffuse ST elevation. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Saddle-shaped morphology is associated with pericarditis."}, {"id": "b", "text": "Diffuse ST elevation is emphasized in this note."}, {"id": "c", "text": "Pericarditis causes only contiguous territorial ST elevation in this note."}, {"id": "d", "text": "ST elevation is absent in pericarditis in this note."}, {"id": "e", "text": "This pattern differs from localized MI territories."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis classically shows diffuse (all-lead) saddle-shaped ST elevation.', 'Pericarditis - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected pericarditis and PR depression, which statements are correct? (Select all that apply)', 'For suspected pericarditis and PR depression, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "PR elevation is the classic early finding in this note."}, {"id": "b", "text": "PR direction contrasts with ST elevation in this note."}, {"id": "c", "text": "It appears early in the disease course."}, {"id": "d", "text": "PR depression is a classic finding in this note."}, {"id": "e", "text": "PR changes are irrelevant in pericarditis in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: PR depression is a classic early pericarditis finding and opposite ST direction.', 'Pericarditis - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around No reciprocal changes. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around No reciprocal changes. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Reciprocal changes support MI rather than pericarditis."}, {"id": "b", "text": "Pericarditis requires reciprocal ST depression in this note."}, {"id": "c", "text": "This distinction is used in pericarditis vs MI comparison."}, {"id": "d", "text": "Reciprocal changes have no differential value in this note."}, {"id": "e", "text": "Reciprocal ST depression is absent in pericarditis in this note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis has no reciprocal ST depression, unlike MI.', 'Pericarditis - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues support Later EKG evolution rather than MI? (Select all that apply)', 'Which clues support Later EKG evolution rather than MI? (Select all that apply)', '[{"id": "a", "text": "T-wave inversion can occur later."}, {"id": "b", "text": "Electrical alternans can accompany large effusion."}, {"id": "c", "text": "Electrical alternans excludes effusion in this note."}, {"id": "d", "text": "EKG pattern is fixed and never evolves in this note."}, {"id": "e", "text": "EKG pattern evolves over time in pericarditis."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: T-wave inversion may appear in later stages; electrical alternans can appear with large effusion.', 'Pericarditis - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment of chest pain, which observations align with Pericarditis vs MI pain differences? (Select all that apply)', 'During reassessment of chest pain, which observations align with Pericarditis vs MI pain differences? (Select all that apply)', '[{"id": "a", "text": "MI pain is generally not position-dependent in this note."}, {"id": "b", "text": "MI pain improves when leaning forward in this note."}, {"id": "c", "text": "Pericarditis pain is often pleuritic and positional in this note."}, {"id": "d", "text": "MI pain is described as pressure-like/crushing."}, {"id": "e", "text": "Pericarditis pain is classically crushing pressure in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis pain is gradual, sharp, pleuritic, and positional; MI pain is sudden, crushing, pressure-like, and non-positional.', 'Pericarditis - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Pericarditis vs MI EKG/lab clues. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Pericarditis vs MI EKG/lab clues. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Troponin is never elevated in any pericarditis scenario in this note."}, {"id": "b", "text": "Troponin may be mildly elevated in myopericarditis but higher in MI."}, {"id": "c", "text": "Q waves are a pericarditis hallmark in this note."}, {"id": "d", "text": "Localized ST elevation with reciprocal changes supports MI."}, {"id": "e", "text": "Diffuse ST elevation with PR depression supports pericarditis."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis: diffuse ST elevation + PR depression + absent Q waves; MI: localized ST elevation, reciprocal changes, Q waves in STEMI, higher troponin rise.', 'Pericarditis - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected pericarditis and First-line therapy, which statements are correct? (Select all that apply)', 'For suspected pericarditis and First-line therapy, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "NSAIDs are first-line in this note."}, {"id": "b", "text": "Opioids are listed as definitive first-line therapy in this note."}, {"id": "c", "text": "Colchicine is added to reduce recurrence risk."}, {"id": "d", "text": "Combination therapy is emphasized for acute management."}, {"id": "e", "text": "Colchicine is contraindicated in all pericarditis in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: First-line treatment is NSAIDs (ibuprofen/aspirin) plus colchicine to reduce recurrence risk.', 'Pericarditis - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Activity guidance. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Activity guidance. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "High-intensity exercise accelerates recovery in this note."}, {"id": "b", "text": "Rest is recommended in acute pericarditis."}, {"id": "c", "text": "No activity limits are needed during acute phase in this note."}, {"id": "d", "text": "Strenuous exercise should be avoided until symptom-free."}, {"id": "e", "text": "Activity guidance is part of initial management."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Rest and activity restriction are recommended during the acute phase; avoid strenuous exercise until symptom-free.', 'Pericarditis - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues support Second-line steroids rather than MI? (Select all that apply)', 'Which clues support Second-line steroids rather than MI? (Select all that apply)', '[{"id": "a", "text": "Prednisone is not first-line in routine cases in this note."}, {"id": "b", "text": "Specific etiologies (e.g., SLE) can justify steroid use."}, {"id": "c", "text": "Steroids are mandatory first-line for all cases in this note."}, {"id": "d", "text": "SLE-related pericarditis should avoid steroids in this note."}, {"id": "e", "text": "Steroids are considered when first-line therapy fails."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Corticosteroids are reserved when NSAID/colchicine fails or for specific causes like SLE.', 'Pericarditis - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment of chest pain, which observations align with Cause-specific caveats? (Select all that apply)', 'During reassessment of chest pain, which observations align with Cause-specific caveats? (Select all that apply)', '[{"id": "a", "text": "Uremic pericarditis is a context to avoid NSAIDs in this note."}, {"id": "b", "text": "TB management is excluded from pericarditis care in this note."}, {"id": "c", "text": "Bacterial pericarditis requires IV antibiotics in this note."}, {"id": "d", "text": "All causes are treated identically with NSAID monotherapy in this note."}, {"id": "e", "text": "TB pericarditis requires anti-TB therapy in this note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Avoid NSAIDs in uremic pericarditis; use IV antibiotics for bacterial causes and anti-TB therapy for TB.', 'Pericarditis - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Tamponade emergency bridge. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Tamponade emergency bridge. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Beck triad is listed with tamponade complication."}, {"id": "b", "text": "Tamponade in pericarditis is managed with observation only in this note."}, {"id": "c", "text": "Beck triad excludes tamponade in this note."}, {"id": "d", "text": "Emergency pericardiocentesis is required for tamponade."}, {"id": "e", "text": "Tamponade is life-threatening in this note."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Tamponade complication is identified by Beck triad and treated with emergency pericardiocentesis.', 'Pericarditis - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected pericarditis and Dressler management caveat, which statements are correct? (Select all that apply)', 'For suspected pericarditis and Dressler management caveat, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "NSAID plus colchicine is recommended for Dressler syndrome in this note."}, {"id": "b", "text": "Dressler is autoimmune and post-MI/surgery in this note."}, {"id": "c", "text": "Routine anticoagulation is first-line Dressler treatment in this note."}, {"id": "d", "text": "Anticoagulants are avoided because of pericardial bleeding risk."}, {"id": "e", "text": "Dressler treatment excludes NSAIDs in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Dressler syndrome is treated with NSAIDs + colchicine and anticoagulants are avoided due to bleeding risk into pericardium.', 'Pericarditis - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around NCLEX triage anchor. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around NCLEX triage anchor. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Monitor for progression to effusion/tamponade."}, {"id": "b", "text": "Pain pattern and position response are triage anchors."}, {"id": "c", "text": "Tamponade surveillance is unnecessary in pericarditis in this note."}, {"id": "d", "text": "Friction rub and EKG clues are high-yield assessments."}, {"id": "e", "text": "Triage can ignore EKG in chest pain with suspected pericarditis in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: In suspected pericarditis, prioritize pain pattern recognition, friction rub assessment, EKG interpretation, and tamponade surveillance.', 'Pericarditis - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues support Hallmark synthesis rather than MI? (Select all that apply)', 'Which clues support Hallmark synthesis rather than MI? (Select all that apply)', '[{"id": "a", "text": "Pleuritic positional pain is a hallmark in this note."}, {"id": "b", "text": "Reciprocal ST depression is a hallmark of pericarditis in this note."}, {"id": "c", "text": "Diffuse ST elevation with PR depression supports diagnosis."}, {"id": "d", "text": "Localized-only ST elevation is required for diagnosis in this note."}, {"id": "e", "text": "Friction rub is a hallmark in this note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Core hallmarks are pleuritic positional chest pain, friction rub, diffuse ST elevation, PR depression, and absent reciprocal ST changes.', 'Pericarditis - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment of chest pain, which observations align with Definition? (Select all that apply)', 'During reassessment of chest pain, which observations align with Definition? (Select all that apply)', '[{"id": "a", "text": "Pericarditis involves inflammation of pericardial layers."}, {"id": "b", "text": "Inflammation can progress to pericardial effusion."}, {"id": "c", "text": "Pericarditis is confined to coronary arteries in this note."}, {"id": "d", "text": "Pericarditis is inflammation of heart valves in this note."}, {"id": "e", "text": "The pericardium is the sac around the heart."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis is inflammation of the pericardium, the fibrous sac surrounding the heart.', 'Pericarditis - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Disease course. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Disease course. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Pericarditis is always single-episode and never recurrent in this note."}, {"id": "b", "text": "Chronic constrictive forms are also listed."}, {"id": "c", "text": "Constrictive disease is unrelated to pericarditis in this note."}, {"id": "d", "text": "Recurrent forms are described in the note."}, {"id": "e", "text": "Acute forms are described in the note."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis can be acute, recurrent, or chronic constrictive.', 'Pericarditis - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected pericarditis and Effusion complication, which statements are correct? (Select all that apply)', 'For suspected pericarditis and Effusion complication, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Effusion improves cardiac filling in this note."}, {"id": "b", "text": "Tamponade is a harmless expected phase in this note."}, {"id": "c", "text": "Large effusions can compress the heart."}, {"id": "d", "text": "Pericardial inflammation can produce effusion."}, {"id": "e", "text": "Tamponade is a life-threatening pericarditis complication."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Fluid accumulation can cause pericardial effusion, and large effusions can lead to cardiac tamponade.', 'Pericarditis - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Common causes. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Common causes. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Coxsackievirus/Echovirus/Influenza are listed viral examples."}, {"id": "b", "text": "Viral etiologies are highlighted as most common."}, {"id": "c", "text": "Idiopathic cases are frequent in this note."}, {"id": "d", "text": "Pericarditis is almost never viral in this note."}, {"id": "e", "text": "Idiopathic causes are excluded in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Viral causes are most common, and many cases are idiopathic.', 'Pericarditis - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues support Systemic/infectious causes rather than MI? (Select all that apply)', 'Which clues support Systemic/infectious causes rather than MI? (Select all that apply)', '[{"id": "a", "text": "Pericarditis is unrelated to renal failure in this note."}, {"id": "b", "text": "SLE/RA/scleroderma are autoimmune causes in the note."}, {"id": "c", "text": "Hydralazine and Procainamide are listed medication causes."}, {"id": "d", "text": "TB and S. aureus are listed infectious causes."}, {"id": "e", "text": "Radiation cannot cause pericarditis in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Bacterial TB/S. aureus, autoimmune disease, uremia, malignancy, radiation, trauma, surgery, and medications are listed causes.', 'Pericarditis - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment of chest pain, which observations align with Dressler syndrome timing? (Select all that apply)', 'During reassessment of chest pain, which observations align with Dressler syndrome timing? (Select all that apply)', '[{"id": "a", "text": "Dressler syndrome can occur after MI."}, {"id": "b", "text": "Dressler syndrome is bacterial endocarditis in this note."}, {"id": "c", "text": "Dressler syndrome occurs immediately during MI in this note."}, {"id": "d", "text": "Timing is listed as 1–6 weeks post-event."}, {"id": "e", "text": "Cardiac surgery is another trigger in this note."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Dressler syndrome is autoimmune pericarditis occurring 1–6 weeks after MI or cardiac surgery.', 'Pericarditis - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Classic pain profile. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Classic pain profile. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Leaning forward worsens pain in this note."}, {"id": "b", "text": "Pain worsens when lying flat in this note."}, {"id": "c", "text": "Pain is position-independent pressure pain in this note."}, {"id": "d", "text": "Pain worsens with inspiration in this note."}, {"id": "e", "text": "Leaning forward provides relief in this note."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis pain is sharp/pleuritic, worse with inspiration and lying flat, and relieved by sitting up/leaning forward.', 'Pericarditis - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected pericarditis and Radiation and associated symptoms, which statements are correct? (Select all that apply)', 'For suspected pericarditis and Radiation and associated symptoms, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Viral-associated constitutional symptoms may occur."}, {"id": "b", "text": "Dyspnea can accompany pericarditis."}, {"id": "c", "text": "Trapezius radiation excludes pericarditis in this note."}, {"id": "d", "text": "Dyspnea never occurs in pericarditis in this note."}, {"id": "e", "text": "Left shoulder/trapezius radiation is described."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Pain can radiate to left shoulder/trapezius; fever, malaise, myalgia, and dyspnea can occur.', 'Pericarditis - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Friction rub hallmark. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Friction rub hallmark. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Best heard at left sternal border while leaning forward."}, {"id": "b", "text": "Rub is best heard at the carotids in this note."}, {"id": "c", "text": "Friction rub is a definitive MI finding in this note."}, {"id": "d", "text": "The rub is described as high-pitched scratchy/grating."}, {"id": "e", "text": "Friction rub is pathognomonic in this note."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericardial friction rub is pathognomonic: high-pitched scratchy/grating, best heard at left sternal border with patient leaning forward.', 'Pericarditis - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues support Rub nuances rather than MI? (Select all that apply)', 'Which clues support Rub nuances rather than MI? (Select all that apply)', '[{"id": "a", "text": "Persistent rub is required throughout all stages in this note."}, {"id": "b", "text": "Rub can disappear when effusion increases."}, {"id": "c", "text": "Triphasic friction rub may be present."}, {"id": "d", "text": "Loss of rub does not exclude worsening complications."}, {"id": "e", "text": "Effusion makes rub louder by increasing friction in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: The rub may be triphasic and can disappear if effusion develops as fluid separates pericardial layers.', 'Pericarditis - NCLEX', true, 84, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment of chest pain, which observations align with Diffuse ST elevation? (Select all that apply)', 'During reassessment of chest pain, which observations align with Diffuse ST elevation? (Select all that apply)', '[{"id": "a", "text": "Pericarditis causes only contiguous territorial ST elevation in this note."}, {"id": "b", "text": "ST elevation is absent in pericarditis in this note."}, {"id": "c", "text": "This pattern differs from localized MI territories."}, {"id": "d", "text": "Diffuse ST elevation is emphasized in this note."}, {"id": "e", "text": "Saddle-shaped morphology is associated with pericarditis."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis classically shows diffuse (all-lead) saddle-shaped ST elevation.', 'Pericarditis - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for PR depression. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for PR depression. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "PR changes are irrelevant in pericarditis in this note."}, {"id": "b", "text": "PR direction contrasts with ST elevation in this note."}, {"id": "c", "text": "PR elevation is the classic early finding in this note."}, {"id": "d", "text": "It appears early in the disease course."}, {"id": "e", "text": "PR depression is a classic finding in this note."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: PR depression is a classic early pericarditis finding and opposite ST direction.', 'Pericarditis - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected pericarditis and No reciprocal changes, which statements are correct? (Select all that apply)', 'For suspected pericarditis and No reciprocal changes, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "This distinction is used in pericarditis vs MI comparison."}, {"id": "b", "text": "Reciprocal changes have no differential value in this note."}, {"id": "c", "text": "Reciprocal changes support MI rather than pericarditis."}, {"id": "d", "text": "Pericarditis requires reciprocal ST depression in this note."}, {"id": "e", "text": "Reciprocal ST depression is absent in pericarditis in this note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis has no reciprocal ST depression, unlike MI.', 'Pericarditis - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Later EKG evolution. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Later EKG evolution. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Electrical alternans excludes effusion in this note."}, {"id": "b", "text": "T-wave inversion can occur later."}, {"id": "c", "text": "EKG pattern evolves over time in pericarditis."}, {"id": "d", "text": "EKG pattern is fixed and never evolves in this note."}, {"id": "e", "text": "Electrical alternans can accompany large effusion."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: T-wave inversion may appear in later stages; electrical alternans can appear with large effusion.', 'Pericarditis - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues support Pericarditis vs MI pain differences rather than MI? (Select all that apply)', 'Which clues support Pericarditis vs MI pain differences rather than MI? (Select all that apply)', '[{"id": "a", "text": "MI pain is generally not position-dependent in this note."}, {"id": "b", "text": "Pericarditis pain is often pleuritic and positional in this note."}, {"id": "c", "text": "MI pain is described as pressure-like/crushing."}, {"id": "d", "text": "MI pain improves when leaning forward in this note."}, {"id": "e", "text": "Pericarditis pain is classically crushing pressure in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis pain is gradual, sharp, pleuritic, and positional; MI pain is sudden, crushing, pressure-like, and non-positional.', 'Pericarditis - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment of chest pain, which observations align with Pericarditis vs MI EKG/lab clues? (Select all that apply)', 'During reassessment of chest pain, which observations align with Pericarditis vs MI EKG/lab clues? (Select all that apply)', '[{"id": "a", "text": "Q waves are a pericarditis hallmark in this note."}, {"id": "b", "text": "Localized ST elevation with reciprocal changes supports MI."}, {"id": "c", "text": "Troponin may be mildly elevated in myopericarditis but higher in MI."}, {"id": "d", "text": "Diffuse ST elevation with PR depression supports pericarditis."}, {"id": "e", "text": "Troponin is never elevated in any pericarditis scenario in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis: diffuse ST elevation + PR depression + absent Q waves; MI: localized ST elevation, reciprocal changes, Q waves in STEMI, higher troponin rise.', 'Pericarditis - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for First-line therapy. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for First-line therapy. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Combination therapy is emphasized for acute management."}, {"id": "b", "text": "NSAIDs are first-line in this note."}, {"id": "c", "text": "Colchicine is added to reduce recurrence risk."}, {"id": "d", "text": "Opioids are listed as definitive first-line therapy in this note."}, {"id": "e", "text": "Colchicine is contraindicated in all pericarditis in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: First-line treatment is NSAIDs (ibuprofen/aspirin) plus colchicine to reduce recurrence risk.', 'Pericarditis - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected pericarditis and Activity guidance, which statements are correct? (Select all that apply)', 'For suspected pericarditis and Activity guidance, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Strenuous exercise should be avoided until symptom-free."}, {"id": "b", "text": "Activity guidance is part of initial management."}, {"id": "c", "text": "High-intensity exercise accelerates recovery in this note."}, {"id": "d", "text": "Rest is recommended in acute pericarditis."}, {"id": "e", "text": "No activity limits are needed during acute phase in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Rest and activity restriction are recommended during the acute phase; avoid strenuous exercise until symptom-free.', 'Pericarditis - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Second-line steroids. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Second-line steroids. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Prednisone is not first-line in routine cases in this note."}, {"id": "b", "text": "Specific etiologies (e.g., SLE) can justify steroid use."}, {"id": "c", "text": "SLE-related pericarditis should avoid steroids in this note."}, {"id": "d", "text": "Steroids are mandatory first-line for all cases in this note."}, {"id": "e", "text": "Steroids are considered when first-line therapy fails."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Corticosteroids are reserved when NSAID/colchicine fails or for specific causes like SLE.', 'Pericarditis - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues support Cause-specific caveats rather than MI? (Select all that apply)', 'Which clues support Cause-specific caveats rather than MI? (Select all that apply)', '[{"id": "a", "text": "Bacterial pericarditis requires IV antibiotics in this note."}, {"id": "b", "text": "TB management is excluded from pericarditis care in this note."}, {"id": "c", "text": "All causes are treated identically with NSAID monotherapy in this note."}, {"id": "d", "text": "TB pericarditis requires anti-TB therapy in this note."}, {"id": "e", "text": "Uremic pericarditis is a context to avoid NSAIDs in this note."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Avoid NSAIDs in uremic pericarditis; use IV antibiotics for bacterial causes and anti-TB therapy for TB.', 'Pericarditis - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment of chest pain, which observations align with Tamponade emergency bridge? (Select all that apply)', 'During reassessment of chest pain, which observations align with Tamponade emergency bridge? (Select all that apply)', '[{"id": "a", "text": "Beck triad excludes tamponade in this note."}, {"id": "b", "text": "Emergency pericardiocentesis is required for tamponade."}, {"id": "c", "text": "Tamponade is life-threatening in this note."}, {"id": "d", "text": "Beck triad is listed with tamponade complication."}, {"id": "e", "text": "Tamponade in pericarditis is managed with observation only in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Tamponade complication is identified by Beck triad and treated with emergency pericardiocentesis.', 'Pericarditis - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is being evaluated for Dressler management caveat. Which findings/actions are appropriate? (Select all that apply)', 'A patient is being evaluated for Dressler management caveat. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "NSAID plus colchicine is recommended for Dressler syndrome in this note."}, {"id": "b", "text": "Dressler treatment excludes NSAIDs in this note."}, {"id": "c", "text": "Routine anticoagulation is first-line Dressler treatment in this note."}, {"id": "d", "text": "Dressler is autoimmune and post-MI/surgery in this note."}, {"id": "e", "text": "Anticoagulants are avoided because of pericardial bleeding risk."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Dressler syndrome is treated with NSAIDs + colchicine and anticoagulants are avoided due to bleeding risk into pericardium.', 'Pericarditis - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected pericarditis and NCLEX triage anchor, which statements are correct? (Select all that apply)', 'For suspected pericarditis and NCLEX triage anchor, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Monitor for progression to effusion/tamponade."}, {"id": "b", "text": "Friction rub and EKG clues are high-yield assessments."}, {"id": "c", "text": "Pain pattern and position response are triage anchors."}, {"id": "d", "text": "Triage can ignore EKG in chest pain with suspected pericarditis in this note."}, {"id": "e", "text": "Tamponade surveillance is unnecessary in pericarditis in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: In suspected pericarditis, prioritize pain pattern recognition, friction rub assessment, EKG interpretation, and tamponade surveillance.', 'Pericarditis - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Hallmark synthesis. Which items belong in the plan? (Select all that apply)', 'The nurse plans care around Hallmark synthesis. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Friction rub is a hallmark in this note."}, {"id": "b", "text": "Localized-only ST elevation is required for diagnosis in this note."}, {"id": "c", "text": "Diffuse ST elevation with PR depression supports diagnosis."}, {"id": "d", "text": "Reciprocal ST depression is a hallmark of pericarditis in this note."}, {"id": "e", "text": "Pleuritic positional pain is a hallmark in this note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Core hallmarks are pleuritic positional chest pain, friction rub, diffuse ST elevation, PR depression, and absent reciprocal ST changes.', 'Pericarditis - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues support Definition rather than MI? (Select all that apply)', 'Which clues support Definition rather than MI? (Select all that apply)', '[{"id": "a", "text": "The pericardium is the sac around the heart."}, {"id": "b", "text": "Inflammation can progress to pericardial effusion."}, {"id": "c", "text": "Pericarditis is confined to coronary arteries in this note."}, {"id": "d", "text": "Pericarditis involves inflammation of pericardial layers."}, {"id": "e", "text": "Pericarditis is inflammation of heart valves in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis is inflammation of the pericardium, the fibrous sac surrounding the heart.', 'Pericarditis - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment of chest pain, which observations align with Disease course? (Select all that apply)', 'During reassessment of chest pain, which observations align with Disease course? (Select all that apply)', '[{"id": "a", "text": "Acute forms are described in the note."}, {"id": "b", "text": "Chronic constrictive forms are also listed."}, {"id": "c", "text": "Constrictive disease is unrelated to pericarditis in this note."}, {"id": "d", "text": "Pericarditis is always single-episode and never recurrent in this note."}, {"id": "e", "text": "Recurrent forms are described in the note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Pericarditis can be acute, recurrent, or chronic constrictive.', 'Pericarditis - NCLEX', true, 100, 1, true);
END $$;
COMMIT;